import { execSync } from 'child_process';
import fs from 'fs';
const TOKG = process.env.GH_TOKEN;
function ghPut(path, buf, msg) {
  const url = `https://api.github.com/repos/raimis079-creator/petshop-bridge/contents/${path}`;
  let sha=''; try { const j=JSON.parse(execSync(`curl -s -H "Authorization: Bearer ${TOKG}" "${url}"`).toString()); if(j.sha) sha=j.sha; } catch(e){}
  fs.writeFileSync('/tmp/p.json', JSON.stringify({ message: msg, content: buf.toString('base64'), ...(sha?{sha}:{}) }));
  execSync(`curl -s -X PUT -H "Authorization: Bearer ${TOKG}" -d @/tmp/p.json "${url}"`, {maxBuffer:20*1024*1024});
}
function sh(c){ try { return execSync(c,{maxBuffer:30*1024*1024}).toString(); } catch(e){ return 'ERR:'+(e.message||'').slice(0,300); } }
const AUTH = Buffer.from((process.env.WP_USER||'').trim()+':'+(process.env.WP_APP_PASS||'').replace(/\s+/g,'')).toString('base64');
const API = 'https://dev.avesa.lt/wp-json/code-snippets/v1/snippets';
const out = {};
const php = `
add_action('wp_loaded', function(){
	if ( ! isset(\$_GET['ps_d206']) ) { return; }
	\$m = sanitize_key(\$_GET['ps_d206']);
	\$t = array(
		WP_PLUGIN_DIR.'/petshop-core/includes/class-pet-profile.php' => '',
		WP_PLUGIN_DIR.'/petshop-core/assets/pet-form.js'             => '',
		WP_PLUGIN_DIR.'/petshop-core/includes/class-pet-ui.php'      => '',
	);
	\$o = array();
	if ( \$m === 'wr206' ) {
		foreach (\$t as \$f => \$b) {
			if ( file_exists(\$f) && ! file_exists(\$f.'.bak-s206') ) copy(\$f, \$f.'.bak-s206');
			\$d = base64_decode(\$b); \$w = file_put_contents(\$f, \$d);
			\$o['w'][basename(\$f)] = (md5(\$d) === md5_file(\$f)) ? 'OK '.\$w : 'MISMATCH';
		}
	} elseif ( \$m === 'rb206' ) {
		foreach (\$t as \$f => \$b) if ( file_exists(\$f.'.bak-s206') ) { copy(\$f.'.bak-s206', \$f); \$o['r'][] = basename(\$f); }
	}
	header('Content-Type: application/json'); echo wp_json_encode(\$o); exit;
});`;
fs.writeFileSync('/tmp/snip.json', JSON.stringify({ name: 'TEMP M8 D206', code: php, scope: 'global', active: true }));
sh(`curl -sk -X POST -H "Authorization: Basic ${AUTH}" -H "Content-Type: application/json" -d @/tmp/snip.json "${API}"`);
const wr = sh('curl -sk --max-time 40 "https://dev.avesa.lt/?ps_d206=wr206"');
try { out.write = JSON.parse(wr); } catch(e){ out.write_raw = wr.slice(0,400); }
out.home = sh('curl -sk -o /dev/null -w "%{http_code}" --max-time 25 "https://dev.avesa.lt/"');
out.acct = sh('curl -sk -o /dev/null -w "%{http_code}" --max-time 25 "https://dev.avesa.lt/my-account/"');
out.rest = sh('curl -sk -o /dev/null -w "%{http_code}" --max-time 25 "https://dev.avesa.lt/wp-json/petshop/v1"');
if (out.home !== '200' || out.acct !== '200' || out.rest !== '200') {
  out.ROLLBACK = sh('curl -sk --max-time 40 "https://dev.avesa.lt/?ps_d206=rb206"').slice(0,300);
  out.after = sh('curl -sk -o /dev/null -w "%{http_code}" "https://dev.avesa.lt/"');
}
const kphp = `add_action('wp_loaded', function(){ if(!isset(\$_GET['ps_kc'])||\$_GET['ps_kc']!=='Rr3Ww8Yy'){return;} global \$wpdb; \$n=\$wpdb->query("DELETE FROM {\$wpdb->prefix}snippets WHERE name LIKE 'TEMP M8%'"); echo wp_json_encode(array('d'=>\$n)); exit; });`;
fs.writeFileSync('/tmp/k.json', JSON.stringify({ name:'TEMP M8 Kill vC', code:kphp, scope:'global', active:true }));
sh(`curl -sk -X POST -H "Authorization: Basic ${AUTH}" -H "Content-Type: application/json" -d @/tmp/k.json "${API}"`);
out.kill = sh('curl -sk --max-time 25 "https://dev.avesa.lt/?ps_kc=Rr3Ww8Yy"').slice(0,80);
ghPut('screenshots/m8_d206.json', Buffer.from(JSON.stringify(out)), 'd206 deploy');
console.log('DONE');
